// // This SR latch uses NAND gates to implement set and reset functionality. When S is high and R is low, Q should be low; when S is low and R is high, Q should be high; when both S and R are low, the previous state should be maintained; when both S and R are high, the output is defined (but for simulation, you can assume it remains in the previous state).
module SR_latch (  
    input S,  
    input R,  
    output reg Q,  
    output reg Qn  
);  
    always @ (S or R) begin  
        if (S && !R) begin  
            Q = 1;  
            Qn = 0;  
        end else if (!S && R) begin  
            Q = 0;  
            Qn = 1;  
        end else if (!S && !R) begin  
            Q = Q;  
            Qn = Qn;  
        end else begin  
            Q = Q;  
            Qn = Qn;  
        end  
    end  
endmodule
